    60→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
    61→  // Group fields by theme
    62→  const grouped = new Map<Theme, SearchField[]>()
    63→  for (const f of fields) {
    64→    const existing = grouped.get(f.theme)
    65→    if (existing) {
    66→      existing.push(f)
    67→    } else {
    68→      grouped.set(f.theme, [f])
    69→    }
    70→  }
    71→
    72→  // Sort fields within each group alphabetically by label
    73→  for (const group of grouped.values()) {
    74→    group.sort((a, b) => a.label.localeCompare(b.label))
    75→  }
    76→
    77→  // Build ordered result: known themes first, then any unknown themes
    78→  const result: ThemeGroup[] = []
    79→  for (const theme of THEME_ORDER) {
    80→    const group = grouped.get(theme)
    81→    if (group && group.length > 0) {
    82→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
    83→      grouped.delete(theme)
    84→    }
    85→  }
    86→  // Append any remaining themes not in THEME_ORDER
    87→  for (const [theme, group] of grouped) {
    88→    if (group.length > 0) {
    89→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
    90→    }
    91→  }
    92→
    93→  return result
    94→}
