// intPtr returns a pointer to an int literal.
func intPtr(v int) *int { return &v }

// strPtr returns a pointer to a string, or nil if the string is empty.
func strPtr(s string) *string {
	if s == "" {
		return nil
	}
	return &s
}

// isBinaryEnum returns true if the options are exactly [{Value:"0"}, {Value:"1"}].
func isBinaryEnum(opts []search.EnumOption) bool {
	if len(opts) != 2 {
		return false
	}
	return opts[0].Value == "0" && opts[1].Value == "1"
}

// unitsToSearchFieldUnit maps the search engine's Units string to a GraphQL SearchFieldUnit.
// Returns nil when no unit applies.
func unitsToSearchFieldUnit(units string, bounds *search.NumericBounds) *model.SearchFieldUnit {
	switch units {
	case "USD":
		u := model.SearchFieldUnitDollars
		return &u
	case "miles":
		u := model.SearchFieldUnitMiles
		return &u
	}
	// Percentage: fields stored as 0.0–1.0 with no explicit unit label.
	if units == "" && bounds != nil && bounds.Min != nil && bounds.Max != nil &&
		*bounds.Min == 0.0 && *bounds.Max == 1.0 {
		u := model.SearchFieldUnitPercentage
		return &u
	}
	return nil
}

